/**
 * 人物关系图可视化
 * 使用 graphology 实现力导向图
 * 节点：人物，边：人物关系
 * 支持点击查看详情
 */

import { useEffect, useRef, useState, useCallback } from 'react'
import { Card, Button, Space, message, Spin, Drawer, Descriptions, Tag } from 'antd'
import { ReloadOutlined } from '@ant-design/icons'
import Graph from 'graphology'
import forceAtlas2 from 'graphology-layout-forceatlas2'

interface GraphNode {
  id: string
  label: string
  mbti?: string
  type?: string
}

interface RawRelationship {
  from: string
  to: string
  type: string
  strength: number
  development?: unknown[]
}

interface GraphEdge {
  id: string
  source: string
  target: string
  label: string
  weight: number
  from: string
  to: string
  type: string
  strength: number
}

interface CharacterGraphProps {
  projectRoot: string | null
  onNodeClick?: (characterName: string) => void
}

const REL_TYPE_COLORS: Record<string, string> = {
  mentor: '#1677ff',
  rival: '#ff4d4f',
  love: '#eb2f96',
  family: '#52c41a',
  friend: '#13c2c2',
  master: '#722ed1',
  enemy: '#d4380d',
}

const CharacterGraph: React.FC<CharacterGraphProps> = ({ projectRoot }) => {
  const [loading, setLoading] = useState(false)
  const [graphData, setGraphData] = useState<{
    nodes: GraphNode[]
    edges: GraphEdge[]
  } | null>(null)
  const [selectedNode, setSelectedNode] = useState<GraphNode | null>(null)
  const [drawerVisible, setDrawerVisible] = useState(false)

  const loadGraphData = useCallback(async () => {
    if (!projectRoot) return
    setLoading(true)
    try {
      // 读取 relationships.yaml
      const relFile = `${projectRoot}/relationships.yaml`
      const relResult = await window.electronAPI.yaml.read(relFile)
      const relData = relResult.success
        ? (relResult.data as Record<string, unknown>)
        : { relationships: [] }
      const rels = (relData.relationships as RawRelationship[]) || []

      // 读取角色基本信息
      const charsDir = `${projectRoot}/characters`
      const charFilesResult = await window.electronAPI.readdir(charsDir)
      if (!charFilesResult.success) { console.error('读取characters目录失败:', charFilesResult.error); }
      const charFiles = charFilesResult.data || []
      const charInfoMap: Record<string, GraphNode> = {}

      for (const file of charFiles) {
        if (file.isFile && file.name.endsWith('.yaml')) {
          const charResult = await window.electronAPI.yaml.read(`${charsDir}/${file.name}`)
          if (charResult.success && charResult.data) {
            const data = charResult.data as Record<string, unknown>
            const name = String(data.name || file.name.replace('.yaml', ''))
            charInfoMap[name] = {
              id: name,
              label: name,
              mbti: data.mbti as string | undefined,
              type: 'character',
            }
          }
        }
      }

      // 构建节点（所有出现在关系中的角色）
      const nodeSet = new Set<string>()
      for (const rel of rels) {
        nodeSet.add(rel.from)
        nodeSet.add(rel.to)
      }

      const nodes: GraphNode[] = Array.from(nodeSet).map(name => {
        const info = charInfoMap[name] || {}
        return {
          id: name,
          label: name,
          mbti: info.mbti,
          type: info.type,
        }
      })

      const edges: GraphEdge[] = rels.map((rel: RawRelationship, idx: number) => ({
        id: `edge-${idx}`,
        source: String(rel.from || ''),
        target: String(rel.to || ''),
        from: String(rel.from || ''),
        to: String(rel.to || ''),
        label: String(rel.type || ''),
        type: String(rel.type || ''),
        weight: (rel.strength as number) || 0.5,
        strength: (rel.strength as number) || 0.5,
      }))

      setGraphData({ nodes, edges })
    } catch (error) {
      console.error('加载关系图失败:', error)
      message.error('加载关系图失败')
    } finally {
      setLoading(false)
    }
  }, [projectRoot])

  useEffect(() => {
    loadGraphData()
  }, [loadGraphData])

  const handleNodeClick = useCallback((nodeId: string) => {
    setSelectedNode(prev => graphData?.nodes.find(n => n.id === nodeId) || prev)
    setDrawerVisible(true)
  }, [graphData])

  if (!projectRoot) {
    return (
      <div style={{ padding: 40, textAlign: 'center', color: '#999' }}>
        请先打开一个小说项目
      </div>
    )
  }

  if (loading) {
    return (
      <div style={{ padding: 40, textAlign: 'center' }}>
        <Spin tip="加载关系图..." />
      </div>
    )
  }

  if (!graphData || graphData.nodes.length === 0) {
    return (
      <div style={{ padding: 40, textAlign: 'center' }}>
        <div style={{ color: '#999', marginBottom: 16 }}>
          暂无人物关系数据
        </div>
        <Button icon={<ReloadOutlined />} onClick={loadGraphData}>
          刷新
        </Button>
      </div>
    )
  }

  // 简单的 SVG 力导向图实现
  return (
    <div style={{ height: '100%', display: 'flex', flexDirection: 'column' }}>
      <div
        style={{
          padding: '8px 16px',
          borderBottom: '1px solid #e8e8e8',
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'center',
        }}
      >
        <span style={{ fontSize: 13 }}>
          人物关系图 · {graphData.nodes.length} 人 / {graphData.edges.length} 条关系
        </span>
        <Space>
          <Button size="small" icon={<ReloadOutlined />} onClick={loadGraphData}>
            刷新
          </Button>
        </Space>
      </div>

      <ForceGraph
        nodes={graphData.nodes}
        edges={graphData.edges}
        onNodeClick={handleNodeClick}
      />

      <Drawer
        title={selectedNode?.label}
        open={drawerVisible}
        onClose={() => setDrawerVisible(false)}
        width={300}
      >
        {selectedNode && (
          <Descriptions column={1} size="small">
            <Descriptions.Item label="名称">{selectedNode.label}</Descriptions.Item>
            {selectedNode.mbti && (
              <Descriptions.Item label="MBTI">
                <Tag color="purple">{selectedNode.mbti}</Tag>
              </Descriptions.Item>
            )}
            <Descriptions.Item label="相关关系">
              <div style={{ display: 'flex', flexWrap: 'wrap', gap: 4 }}>
                {graphData?.edges
                  .filter(e => e.source === selectedNode.id || e.target === selectedNode.id)
                  .map((edge, idx) => {
                    const other = edge.source === selectedNode.id ? edge.target : edge.source
                    return (
                      <Tag
                        key={idx}
                        color={REL_TYPE_COLORS[edge.label] || 'default'}
                      >
                        {other} ({edge.label})
                      </Tag>
                    )
                  })}
              </div>
            </Descriptions.Item>
          </Descriptions>
        )}
      </Drawer>
    </div>
  )
}

// 简单的 SVG 力导向图组件
interface ForceGraphProps {
  nodes: GraphNode[]
  edges: GraphEdge[]
  onNodeClick: (nodeId: string) => void
}

const ForceGraph: React.FC<ForceGraphProps> = ({ nodes, edges, onNodeClick }) => {
  const containerRef = useRef<HTMLDivElement>(null)
  const [positions, setPositions] = useState<Record<string, { x: number; y: number }>>({})
  const [dragging, setDragging] = useState<string | null>(null)

  // 初始化力导向布局
  useEffect(() => {
    if (nodes.length === 0) return

    const graph = new Graph()

    // 添加节点
    for (const node of nodes) {
      graph.addNode(node.id, {
        label: node.label,
        x: Math.random() * 400 + 100,
        y: Math.random() * 300 + 100,
        size: 20,
        color: '#1890ff',
      })
    }

    // 添加边
    for (const edge of edges) {
      if (graph.hasNode(edge.source) && graph.hasNode(edge.target)) {
        try {
          graph.addEdge(edge.source, edge.target, {
            label: edge.label,
            size: edge.weight * 3 + 1,
            color: REL_TYPE_COLORS[edge.label] || '#999',
          })
        } catch {
          // 边已存在则跳过
        }
      }
    }

    // 运行 ForceAtlas2
    if (graph.order > 0) {
      try {
        forceAtlas2.assign(graph, {
          iterations: 100,
          settings: {
            gravity: 1,
            scalingRatio: 10,
            strongGravityMode: true,
          },
        })
      } catch (e) {
        console.warn('ForceAtlas2 布局失败，使用随机位置:', e)
      }
    }

    // 提取位置
    const pos: Record<string, { x: number; y: number }> = {}
    graph.forEachNode((nodeId, attrs) => {
      pos[nodeId] = { x: (attrs.x as number) || 0, y: (attrs.y as number) || 0 }
    })

    setPositions(pos)
  }, [nodes, edges])

  if (nodes.length === 0) return null

  // 计算 bounds
  const posValues = Object.values(positions)
  if (posValues.length === 0) return null

  const minX = Math.min(...posValues.map(p => p.x))
  const maxX = Math.max(...posValues.map(p => p.x))
  const minY = Math.min(...posValues.map(p => p.y))
  const maxY = Math.max(...posValues.map(p => p.y))
  const rangeX = maxX - minX || 1
  const rangeY = maxY - minY || 1

  const width = 500
  const height = 400
  const padding = 40
  const scaleX = (width - 2 * padding) / rangeX
  const scaleY = (height - 2 * padding) / rangeY

  const getX = (x: number) => (x - minX) * scaleX + padding
  const getY = (y: number) => (y - minY) * scaleY + padding

  return (
    <div
      ref={containerRef}
      style={{ flex: 1, overflow: 'auto', background: '#fafafa' }}
    >
      <svg width={width} height={height} style={{ cursor: 'grab' }}>
        {/* 绘制边 */}
        {edges.map(edge => {
          const fromPos = positions[edge.source]
          const toPos = positions[edge.target]
          if (!fromPos || !toPos) return null

          const x1 = getX(fromPos.x)
          const y1 = getY(fromPos.y)
          const x2 = getX(toPos.x)
          const y2 = getY(toPos.y)

          // 计算边的中点（用于放置标签）
          const midX = (x1 + x2) / 2
          const midY = (y1 + y2) / 2

          return (
            <g key={edge.id}>
              <line
                x1={x1}
                y1={y1}
                x2={x2}
                y2={y2}
                stroke={REL_TYPE_COLORS[edge.label] || '#999'}
                strokeWidth={Math.max(edge.weight * 3 + 1, 1)}
                strokeOpacity={0.6}
              />
              <text
                x={midX}
                y={midY - 5}
                textAnchor="middle"
                fontSize={10}
                fill={REL_TYPE_COLORS[edge.label] || '#999'}
                style={{ pointerEvents: 'none' }}
              >
                {edge.label}
              </text>
            </g>
          )
        })}

        {/* 绘制节点 */}
        {nodes.map(node => {
          const pos = positions[node.id]
          if (!pos) return null

          const cx = getX(pos.x)
          const cy = getY(pos.y)

          return (
            <g
              key={node.id}
              style={{ cursor: 'pointer' }}
              onClick={() => onNodeClick(node.id)}
            >
              <circle
                cx={cx}
                cy={cy}
                r={16}
                fill="#1890ff"
                stroke="#fff"
                strokeWidth={2}
              />
              <text
                x={cx}
                y={cy + 4}
                textAnchor="middle"
                fontSize={11}
                fill="#fff"
                style={{ pointerEvents: 'none', fontWeight: 'bold' }}
              >
                {node.label.slice(0, 2)}
              </text>
              <text
                x={cx}
                y={cy - 22}
                textAnchor="middle"
                fontSize={11}
                fill="#333"
                style={{ pointerEvents: 'none' }}
              >
                {node.label}
              </text>
            </g>
          )
        })}
      </svg>

      {/* 图例 */}
      <div
        style={{
          padding: '8px 16px',
          fontSize: 11,
          color: '#666',
          borderTop: '1px solid #e8e8e8',
          display: 'flex',
          gap: 12,
          flexWrap: 'wrap',
        }}
      >
        {Object.entries(REL_TYPE_COLORS).map(([type, color]) => (
          <span key={type} style={{ display: 'flex', alignItems: 'center', gap: 4 }}>
            <span
              style={{
                display: 'inline-block',
                width: 16,
                height: 2,
                background: color,
              }}
            />
            {type}
          </span>
        ))}
      </div>
    </div>
  )
}

export default CharacterGraph

/**
 * 项目管理器
 * 创建新项目、打开项目、项目列表
 */

import path from 'path'

import { useState, useEffect } from 'react'
import {
  Modal,
  Form,
  Input,
  Select,
  Button,
  Space,
  Divider,
  message,
  List,
  Card,
  Tag,
  Empty,
} from 'antd'
import {
  PlusOutlined,
  FolderOpenOutlined,
  FileOutlined,
  DeleteOutlined,
  ProjectOutlined,
} from '@ant-design/icons'
import factsStore from '../db'

interface ProjectInfo {
  name: string
  path: string
  genre: string
  status: string
  lastModified: string
}

interface ProjectManagerProps {
  visible: boolean
  mode?: 'create' | 'list'
  onClose: () => void
  onProjectOpened: (projectPath: string) => void
}

// 默认项目结构
const DEFAULT_PROJECT_STRUCTURE = {
  plots: {
    '第一卷_觉醒': {
      '_plan.yaml': `# 第一卷：觉醒

## 卷概要
重生少年林枫，在修仙世界重新开始。

## 主要线索
- 林枫重生，改变命运
- 青云宗入门测试
- 发现血魔宗阴谋

## 章节规划
- 第1-10章：重生与入门
- 第11-30章：成长与冲突
- 第31-50章：揭露阴谋
`,
    },
  },
  characters: {},
  settings: {},
  facts: {
    characters_facts: {},
    plot_facts: {
      伏笔清单: [],
    },
    settings_facts: {},
  },
  'relationships.yaml': `# 人物关系索引
relationships: []
`,
  'project.yaml': '',
}

const GENRE_OPTIONS = [
  { value: 'xianxia', label: '玄幻修仙' },
  { value: 'urban', label: '都市异能' },
  { value: 'game', label: '游戏世界' },
  { value: 'scifi', label: '科幻末世' },
  { value: 'fantasy', label: '奇幻冒险' },
  { value: 'romance', label: '言情' },
  { value: 'xuanhuan', label: '玄幻爽文' },
]

const ProjectManager: React.FC<ProjectManagerProps> = ({
  visible,
  mode: initialMode,
  onClose,
  onProjectOpened,
}) => {
  const [mode, setMode] = useState<'create' | 'list'>(initialMode || 'create')
  const [form] = Form.useForm()
  const [creating, setCreating] = useState(false)
  const [recentProjects, setRecentProjects] = useState<ProjectInfo[]>([])

  // 加载最近项目
  const loadRecentProjects = async () => {
    try {
      const result = await window.electronAPI.ai.getSetting('recentProjects', [])
      if (result.success && result.value) {
        setRecentProjects(result.value as ProjectInfo[])
      }
    } catch {
      // ignore
    }
  }

  useEffect(() => {
    if (visible) {
      loadRecentProjects()
      setMode(initialMode || 'create')
    }
  }, [visible, initialMode])

  // 创建新项目
  const handleCreateProject = async () => {
    if (!window.electronAPI) {
      message.error('系统未就绪，请刷新页面或重启应用')
      return
    }
    try {
      const values = await form.validateFields()
      setCreating(true)

      // 弹出目录选择对话框
      const parentDir = await window.electronAPI.openDirectory()
      if (!parentDir || parentDir.trim() === '') {
        setCreating(false)
        return
      }

      const projectName = values.name.replace(/[/\\?%*:|"<>]/g, '_')
      const projectPath = path.join(parentDir, projectName)

      // 创建项目目录结构
      await createProjectStructure(projectPath, values)

      // 添加到最近项目
      const projectInfo: ProjectInfo = {
        name: values.name,
        path: projectPath,
        genre: values.genre,
        status: 'planning',
        lastModified: new Date().toISOString().split('T')[0],
      }

      const updatedRecent = [
        projectInfo,
        ...recentProjects.filter(p => p.path !== projectPath),
      ].slice(0, 10) // 最多保留10个最近项目

      await window.electronAPI.ai.saveSetting('recentProjects', updatedRecent)

      message.success(`项目「${values.name}」创建成功！`)
      onProjectOpened(projectPath)
      onClose()
    } catch (error) {
      console.error('创建项目失败:', error)
      message.error('创建项目失败')
    } finally {
      setCreating(false)
    }
  }

  // 创建项目目录结构
  const createProjectStructure = async (
    projectPath: string,
    projectInfo: Record<string, unknown>
  ) => {
    // project.yaml
    const projectYaml = {
      title: projectInfo.name,
      author: projectInfo.author || '你的名字',
      genre: projectInfo.genre || 'xianxia',
      target_words: projectInfo.targetWords || 200000,
      status: 'planning',
      created: new Date().toISOString().split('T')[0],
      last_modified: new Date().toISOString().split('T')[0],
    }

    // project.yaml
    const yamlResult = await window.electronAPI.yaml.write(
      `${projectPath}/project.yaml`,
      projectYaml
    )
    if (!yamlResult.success) {
      throw new Error(`创建 project.yaml 失败: ${yamlResult.error}`)
    }

    // plots 目录和示例章节
    const plotsPath = path.join(projectPath, 'plots')
    const volumePath = path.join(plotsPath, '第一卷_觉醒')
    const mkdirResult = await window.electronAPI.mkdir(volumePath)
    if (!mkdirResult.success) {
      throw new Error(`创建目录失败: ${mkdirResult.error}`)
    }

    // 示例章节
    const sampleChapter = `# 第一章 重生

睁开眼，熟悉的场景映入眼帘。

这是……青云宗？

林枫猛地坐起身，环顾四周。一切都那么熟悉，却又带着一种说不出的陌生感。

他记得自己明明已经死了，死在血魔宗那场围杀之中。可是现在……

低头看着自己的双手，年轻而有力。这双手，应该已经在五百年前那场大战中化为灰烬了。

\"我……重生了？\"

林枫喃喃自语，眼中闪过一丝复杂的光芒。前世的记忆如潮水般涌来——血魔的背叛、师门的覆灭、以及那场改变一切的决战。

既然上天给了他第二次机会……

这一世，他绝不会再让悲剧重演。

血魔宗，你们等着！
`

    // 示例章节文件
    const writeChapterResult = await window.electronAPI.writeFile(
      path.join(volumePath, '第一章_重生.md'),
      sampleChapter
    )
    if (!writeChapterResult.success) {
      throw new Error(`创建章节文件失败: ${writeChapterResult.error}`)
    }

    const writePlanResult = await window.electronAPI.writeFile(
      path.join(volumePath, '_plan.yaml'),
      DEFAULT_PROJECT_STRUCTURE.plots['第一卷_觉醒']['_plan.yaml']
    )
    if (!writePlanResult.success) {
      throw new Error(`创建章节计划失败: ${writePlanResult.error}`)
    }

    // characters 目录
    const mkdirCharsResult = await window.electronAPI.mkdir(path.join(projectPath, 'characters'))
    if (!mkdirCharsResult.success) {
      throw new Error(`创建 characters 目录失败: ${mkdirCharsResult.error}`)
    }

    // settings 目录
    const mkdirSettingsResult = await window.electronAPI.mkdir(path.join(projectPath, 'settings'))
    if (!mkdirSettingsResult.success) {
      throw new Error(`创建 settings 目录失败: ${mkdirSettingsResult.error}`)
    }

    // facts 目录
    const mkdirFactsResult = await window.electronAPI.mkdir(path.join(projectPath, 'facts'))
    if (!mkdirFactsResult.success) {
      throw new Error(`创建 facts 目录失败: ${mkdirFactsResult.error}`)
    }

    const writeFactsResult = await window.electronAPI.yaml.write(
      path.join(projectPath, 'facts', 'plot_facts.yaml'),
      { 伏笔清单: [] }
    )
    if (!writeFactsResult.success) {
      throw new Error(`创建 plot_facts.yaml 失败: ${writeFactsResult.error}`)
    }

    // relationships.yaml
    const writeRelationshipsResult = await window.electronAPI.writeFile(
      `${projectPath}/relationships.yaml`,
      DEFAULT_PROJECT_STRUCTURE['relationships.yaml']
    )
    if (!writeRelationshipsResult.success) {
      throw new Error(`创建 relationships.yaml 失败: ${writeRelationshipsResult.error}`)
    }
  }

  // 打开最近项目
  const handleOpenRecentProject = (project: ProjectInfo) => {
    onProjectOpened(project.path)
    onClose()
  }

  // 删除最近项目记录
  const handleRemoveRecentProject = async (project: ProjectInfo) => {
    const updated = recentProjects.filter(p => p.path !== project.path)
    setRecentProjects(updated)
    await window.electronAPI.ai.saveSetting('recentProjects', updated)
    message.success('已从列表中移除')
  }

  return (
    <Modal
      title={mode === 'create' ? '📖 创建新项目' : '📂 最近项目'}
      open={visible}
      onCancel={onClose}
      width={600}
      footer={null}
      bodyStyle={{ maxHeight: '70vh', overflow: 'auto' }}
    >
      <div style={{ display: 'flex', gap: 8, marginBottom: 16 }}>
        <Button
          type={mode === 'create' ? 'primary' : 'default'}
          onClick={() => setMode('create')}
        >
          创建新项目
        </Button>
        <Button
          type={mode === 'list' ? 'primary' : 'default'}
          onClick={() => setMode('list')}
        >
          最近项目
        </Button>
      </div>

      {mode === 'create' ? (
        <Form
          form={form}
          layout="vertical"
          initialValues={{
            genre: 'xianxia',
            targetWords: 200000,
            author: '',
          }}
        >
          <Form.Item
            name="name"
            label="项目名称"
            rules={[{ required: true, message: '请输入项目名称' }]}
          >
            <Input placeholder="如：剑仙归来、都市修仙传" />
          </Form.Item>

          <Form.Item name="author" label="作者">
            <Input placeholder="你的笔名（可选）" />
          </Form.Item>

          <Form.Item
            name="genre"
            label="题材类型"
            rules={[{ required: true, message: '请选择题材' }]}
          >
            <Select options={GENRE_OPTIONS} />
          </Form.Item>

          <Form.Item
            name="targetWords"
            label="目标字数"
          >
            <Select
              options={[
                { value: 50000, label: '5万字（短篇）' },
                { value: 100000, label: '10万字（中篇）' },
                { value: 200000, label: '20万字（长篇）' },
                { value: 500000, label: '50万字（超长篇）' },
                { value: 1000000, label: '100万字（百万巨著）' },
              ]}
            />
          </Form.Item>

          <Divider />

          <div style={{ color: '#999', fontSize: 12, marginBottom: 12 }}>
            点击「创建」后将弹出目录选择对话框，请选择项目的保存位置。
            项目将自动创建完整的目录结构。
          </div>

          <Button
            type="primary"
            icon={<PlusOutlined />}
            block
            loading={creating}
            onClick={handleCreateProject}
          >
            选择目录并创建项目
          </Button>
