            <List
              grid={{ gutter: 12, xs: 1, sm: 2 }}
              dataSource={recentProjects}
              renderItem={(project) => (
                <List.Item>
                  <Card
                    size="small"
                    hoverable
                    actions={[
                      <Button
                        key="open"
                        type="link"
                        icon={<FolderOpenOutlined />}
                        onClick={() => handleOpenRecentProject(project)}
                      >
                        打开
                      </Button>,
                      <Button
                        key="remove"
                        type="link"
                        danger
                        icon={<DeleteOutlined />}
                        onClick={() => handleRemoveRecentProject(project)}
                      >
                        移除
                      </Button>,
                    ]}
                  >
                    <Card.Meta
                      avatar={<ProjectOutlined style={{ fontSize: 24, color: '#1890ff' }} />}
                      title={project.name}
                      description={
                        <div style={{ fontSize: 12, color: '#999' }}>
                          <div style={{ marginBottom: 4 }}>
                            <Tag>{GENRE_OPTIONS.find(g => g.value === project.genre)?.label || project.genre}</Tag>
                            <Tag color={project.status === 'writing' ? 'green' : 'orange'}>
                              {project.status === 'writing' ? '创作中' : '规划中'}
                            </Tag>
                          </div>
                          <div style={{ wordBreak: 'break-all', fontSize: 11 }}>
                            {project.path}
                          </div>
                        </div>
                      }
                    />
                  </Card>
                </List.Item>
              )}
            />
          )}
        </div>
      )}
    </Modal>
  )
}

export default ProjectManager

/**
 * 向量语义检索面板
 * 提供相似章节搜索功能
 *
 * 降级方案：基于倒排索引的关键词搜索
 * 当 @xenova/transformers 不可用时自动启用
 */

import { useState, useEffect, useMemo } from 'react'
import {
  Input,
  Button,
  List,
  Card,
  Tag,
  Space,
  message,
  Alert,
  Spin,
  Modal,
  Select,
  Tooltip,
  Checkbox,
  Badge,
} from 'antd'
import {
  SearchOutlined,
  BuildOutlined,
  CheckCircleOutlined,
  WarningOutlined,
  ReloadOutlined,
  FilterOutlined,
} from '@ant-design/icons'

interface SearchResult {
  chapterPath: string
  chapterName: string
  score: number
  snippet: string
  matchedWords: string[]
}

interface ChapterEntry {
  path: string
  name: string
  content: string
}

interface InvertedIndex {
  vocabulary: Map<string, Set<string>> // word -> Set<chapterPath>
  totalDocs: number
  docLengths: Map<string, number>
}

interface VectorSearchPanelProps {
  projectRoot: string | null
  onJumpToChapter?: (chapterPath: string) => void
}

const VectorSearchPanel: React.FC<VectorSearchPanelProps> = ({
  projectRoot,
  onJumpToChapter,
}) => {
  const [query, setQuery] = useState('')
  const [results, setResults] = useState<SearchResult[]>([])
  const [loading, setLoading] = useState(false)
  const [indexLoading, setIndexLoading] = useState(false)
  const [chapters, setChapters] = useState<ChapterEntry[]>([])
  const [invertedIndex, setInvertedIndex] = useState<InvertedIndex | null>(null)
  const [queryMode, setQueryMode] = useState<'AND' | 'OR'>('AND')
  const [chapterRange, setChapterRange] = useState<{ start?: number; end?: number }>({})
  const [showFilters, setShowFilters] = useState(false)
  const [indexStats, setIndexStats] = useState<{ wordCount: number; chapterCount: number } | null>(null)

  // 加载所有章节内容并构建倒排索引
  const loadChaptersAndBuildIndex = async (): Promise<{ chapters: ChapterEntry[]; index: InvertedIndex } | null> => {
    if (!projectRoot) return null

    setIndexLoading(true)
    const loadedChapters: ChapterEntry[] = []

    const readDir = async (dirPath: string) => {
      try {
        const entriesResult = await window.electronAPI.readdir(dirPath)
        if (!entriesResult.success) { console.warn('读取目录失败:', dirPath, entriesResult.error); return; }
        const entries = entriesResult.data || []
        for (const entry of entries) {
          const fullPath = `${dirPath}/${entry.name}`
          if (entry.isDirectory) {
            await readDir(fullPath)
          } else if (entry.isFile && entry.name.endsWith('.md') && !entry.name.startsWith('_')) {
            const contentResult = await window.electronAPI.readFile(fullPath)
            if (contentResult.success && contentResult.content) {
              loadedChapters.push({
                path: fullPath,
                name: entry.name.replace('.md', ''),
                content: contentResult.content,
              })
            }
          }
        }
      } catch (e) {
        console.warn('读取目录失败:', dirPath, e)
      }
    }

    const plotsDir = `${projectRoot}/plots`
    let dirExists = false
    try {
      const r = await window.electronAPI.exists(plotsDir)
      dirExists = !!(r && r.success && r.exists)
    } catch (e) {
      console.warn('exists 调用异常:', e)
    }
    if (dirExists) {
      await readDir(plotsDir)
    }

    if (loadedChapters.length === 0) {
      setIndexLoading(false)
      return null
    }

    setChapters(loadedChapters)

    // 构建倒排索引
    const vocab = new Map<string, Set<string>>()
    const docLengths = new Map<string, number>()

    // 中文分词简单实现（基于字典+规则）
    const tokenize = (text: string): string[] => {
      // 去除标点和空格，转小写
      const clean = text.replace(/[^\w\u4e00-\u9fa5]/g, ' ').toLowerCase()
      // 简单按空格和非汉字字符分割
      const words = clean.split(/[\s,。！？、：；""''【】『』]+/).filter(w => w.length >= 1)
      return words
    }

    for (const ch of loadedChapters) {
      const words = tokenize(ch.content)
      docLengths.set(ch.path, words.length)

      for (const word of words) {
        if (word.length < 1) continue
        if (!vocab.has(word)) {
          vocab.set(word, new Set())
        }
        vocab.get(word)!.add(ch.path)
      }
    }

    const index: InvertedIndex = {
      vocabulary: vocab,
      totalDocs: loadedChapters.length,
      docLengths,
    }

    setInvertedIndex(index)
    setIndexStats({
      wordCount: vocab.size,
      chapterCount: loadedChapters.length,
    })
    setIndexLoading(false)

    return { chapters: loadedChapters, index }
  }

  // 初始化时构建索引
  useEffect(() => {
    if (projectRoot) {
      loadChaptersAndBuildIndex()
    }
  }, [projectRoot])

  // 搜索
  const performSearch = async () => {
    if (!query.trim()) {
      message.warning('请输入搜索内容')
      return
    }
    if (!invertedIndex || chapters.length === 0) {
      message.warning('正在加载索引，请稍候...')
      await loadChaptersAndBuildIndex()
      if (!invertedIndex) return
    }

    setLoading(true)
    setResults([])

    try {
      // 分词
      const queryWords = query
        .toLowerCase()
        .replace(/[^\w\u4e00-\u9fa5]/g, ' ')
        .split(/\s+/)
        .filter(w => w.length >= 1)

      if (queryWords.length === 0) {
        setLoading(false)
        return
      }

      // 找出包含查询词的文档
      const docScores = new Map<string, { score: number; matchedWords: Set<string> }>()

      for (const word of queryWords) {
        const docSet = invertedIndex.vocabulary.get(word)
        if (!docSet) continue

        // IDF 权重（简化版）
        const docFreq = docSet.size
        const idf = Math.log((invertedIndex.totalDocs + 1) / (docFreq + 1))

        for (const docPath of docSet) {
          const docLen = invertedIndex.docLengths.get(docPath) || 1
          const tf = 1 // 简化：每个词出现一次

          if (!docScores.has(docPath)) {
            docScores.set(docPath, { score: 0, matchedWords: new Set() })
          }
          const entry = docScores.get(docPath)!
          entry.score += (tf / docLen) * idf
          entry.matchedWords.add(word)
        }
      }

      // 过滤：AND 模式要求所有词都匹配
      let filteredDocs = Array.from(docScores.entries())

      if (queryMode === 'AND') {
        filteredDocs = filteredDocs.filter(([, entry]) =>
          queryWords.every(w => entry.matchedWords.has(w))
        )
      }

      // 章节范围过滤
      if (chapterRange.start || chapterRange.end) {
        filteredDocs = filteredDocs.filter(([path]) => {
          const ch = chapters.find(c => c.path === path)
          if (!ch) return true
          const match = ch.name.match(/第(\d+)章/)
          if (!match) return true
          const chNum = parseInt(match[1])
          if (chapterRange.start && chNum < chapterRange.start) return false
          if (chapterRange.end && chNum > chapterRange.end) return false
          return true
        })
      }

      // 排序并生成结果
      const searchResults: SearchResult[] = filteredDocs
        .sort((a, b) => b[1].score - a[1].score)
        .slice(0, 10)
        .map(([path, entry]) => {
          const ch = chapters.find(c => c.path === path)
          // 生成片段
          let snippet = ''
          if (ch) {
            const contentLower = ch.content.toLowerCase()
            const firstMatchIdx = Math.min(...queryWords.map(w => contentLower.indexOf(w)).filter(i => i >= 0))
            if (firstMatchIdx >= 0) {
              const start = Math.max(0, firstMatchIdx - 40)
              const end = Math.min(ch.content.length, firstMatchIdx + 100)
              snippet = (start > 0 ? '...' : '') + ch.content.slice(start, end) + (end < ch.content.length ? '...' : '')
            } else {
              snippet = ch.content.slice(0, 120) + '...'
            }
          }

          return {
            chapterPath: path,
            chapterName: ch?.name || path,
            score: entry.score,
            snippet,
            matchedWords: Array.from(entry.matchedWords),
          }
        })

      setResults(searchResults)

      if (searchResults.length === 0) {
        message.info('未找到匹配章节，尝试使用 OR 模式或放宽筛选条件')
      }
    } catch (error) {
      console.error('搜索失败:', error)
      message.error('搜索失败')
    } finally {
      setLoading(false)
    }
  }

  // 重建索引
  const handleRebuildIndex = async () => {
    setInvertedIndex(null)
    setResults([])
    await loadChaptersAndBuildIndex()
    message.success('索引已重建')
  }

  // 高亮匹配的词
  const highlightMatches = (text: string, words: string[]): React.ReactNode => {
    if (!words.length) return text

    let result = text
    const parts: { text: string; highlight: boolean }[] = []

    // 简单高亮实现
    const lowerText = text.toLowerCase()
    const allMatches: { start: number; end: number }[] = []

    for (const word of words) {
      let idx = lowerText.indexOf(word.toLowerCase())
      while (idx >= 0) {
        allMatches.push({ start: idx, end: idx + word.length })
        idx = lowerText.indexOf(word.toLowerCase(), idx + 1)
      }
    }

    if (allMatches.length === 0) return text

    // 合并重叠区间并排序
    allMatches.sort((a, b) => a.start - b.start)
    const merged: { start: number; end: number }[] = []
    for (const m of allMatches) {
      if (merged.length === 0 || merged[merged.length - 1].end < m.start) {
        merged.push(m)
      } else {
        merged[merged.length - 1].end = Math.max(merged[merged.length - 1].end, m.end)
      }
    }

    let lastEnd = 0
    for (const m of merged) {
      if (m.start > lastEnd) {
        parts.push({ text: result.slice(lastEnd, m.start), highlight: false })
      }
      parts.push({ text: result.slice(m.start, m.end), highlight: true })
      lastEnd = m.end
    }
    if (lastEnd < result.length) {
      parts.push({ text: result.slice(lastEnd), highlight: false })
    }

    return (
      <>
        {parts.map((p, i) =>
          p.highlight ? (
            <mark key={i} style={{ background: '#ffe58f', padding: '0 2px' }}>{p.text}</mark>
          ) : (
            <span key={i}>{p.text}</span>
          )
        )}
      </>
    )
  }

  if (!projectRoot) {
    return (
      <div style={{ padding: 40, textAlign: 'center', color: '#999' }}>
        请先打开一个小说项目
      </div>
    )
  }

  return (
    <div style={{ height: '100%', display: 'flex', flexDirection: 'column' }}>
      {/* 头部 */}
      <div style={{ padding: '12px 16px', borderBottom: '1px solid #e8e8e8' }}>
        <div style={{ marginBottom: 10 }}>
          <Space>
            <span style={{ fontSize: 13, fontWeight: 500 }}>🔍 相似章节检索</span>
            {indexStats && (
              <Tag color="green">
                索引: {indexStats.wordCount} 词 / {indexStats.chapterCount} 章
              </Tag>
            )}
          </Space>
        </div>

        {/* 索引状态 */}
        <div style={{ marginBottom: 10, fontSize: 12 }}>
          {indexLoading ? (
            <Tag icon={<Spin size="small" />}>正在构建索引...</Tag>
          ) : invertedIndex ? (
            <Tag color="green" icon={<CheckCircleOutlined />}>
              倒排索引已就绪
            </Tag>
          ) : (
            <Tag color="orange" icon={<WarningOutlined />}>
              索引未构建
            </Tag>
          )}
          <Button
            size="small"
            icon={<ReloadOutlined />}
            onClick={handleRebuildIndex}
            style={{ marginLeft: 8 }}
          >
            重建索引
          </Button>
        </div>

        {/* 搜索框 */}
        <Space direction="vertical" style={{ width: '100%' }}>
          <Input.Search
            placeholder="输入情节描述、角色名或关键词..."
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            onSearch={performSearch}
            loading={loading}
            enterButton={
              <Button type="primary" icon={<SearchOutlined />}>
                搜索
              </Button>
            }
          />
        </Space>

        {/* 搜索选项 */}
        <div style={{ marginTop: 8 }}>
          <Button
            size="small"
            type="text"
            icon={<FilterOutlined />}
            onClick={() => setShowFilters(!showFilters)}
          >
            高级选项 {showFilters ? '▲' : '▼'}
          </Button>
          {showFilters && (
            <div style={{ marginTop: 8, padding: 8, background: '#f5f5f5', borderRadius: 6 }}>
              <Space direction="vertical" style={{ width: '100%' }}>
                <div>
                  <span style={{ fontSize: 11, marginRight: 8 }}>匹配模式：</span>
                  <Select
                    size="small"
                    value={queryMode}
                    onChange={setQueryMode}
                    options={[
                      { value: 'AND', label: 'AND（所有词都匹配）' },
                      { value: 'OR', label: 'OR（任一词匹配）' },
                    ]}
                    style={{ width: 160 }}
                  />
                </div>
                <div style={{ display: 'flex', gap: 8, alignItems: 'center' }}>
                  <span style={{ fontSize: 11 }}>章节范围：</span>
                  <Input
                    size="small"
                    placeholder="起始章"
                    type="number"
                    min={1}
                    style={{ width: 70 }}
                    value={chapterRange.start || ''}
                    onChange={(e) => setChapterRange(prev => ({
                      ...prev,
                      start: e.target.value ? parseInt(e.target.value) : undefined
                    }))}
                  />
                  <span>-</span>
                  <Input
                    size="small"
                    placeholder="结束章"
                    type="number"
                    min={1}
                    style={{ width: 70 }}
                    value={chapterRange.end || ''}
                    onChange={(e) => setChapterRange(prev => ({
                      ...prev,
                      end: e.target.value ? parseInt(e.target.value) : undefined
                    }))}
                  />
                </div>
              </Space>
            </div>
          )}
        </div>

        <Alert
          message="使用倒排索引进行关键词检索，支持 AND/OR 查询和章节范围过滤"
          type="info"
          showIcon
          style={{ marginTop: 8, fontSize: 11 }}
        />
      </div>

      {/* 结果列表 */}
      <div style={{ flex: 1, overflow: 'auto', padding: 16 }}>
        {loading || indexLoading ? (
          <div style={{ textAlign: 'center', padding: 40 }}>
            <Spin tip={indexLoading ? '构建索引中...' : '搜索中...'} />
          </div>
        ) : results.length === 0 ? (
          <div style={{ color: '#999', textAlign: 'center', padding: 40, fontSize: 13 }}>
            {query ? '未找到相似章节' : '输入内容开始搜索'}
          </div>
        ) : (
          <List
            dataSource={results}
            renderItem={(item) => (
              <List.Item
                style={{ cursor: 'pointer' }}
                onClick={() => onJumpToChapter?.(item.chapterPath)}
              >
                <List.Item.Meta
                  title={
                    <Space>
                      <span>{item.chapterName}</span>
                      <Tag color="blue">
                        匹配度 {Math.round(item.score * 100)}%
                      </Tag>
                      {item.matchedWords.slice(0, 3).map(w => (
                        <Tag key={w} color="purple" style={{ fontSize: 10 }}>
                          {w}
                        </Tag>
                      ))}
                    </Space>
                  }
                  description={
                    <div
                      style={{
                        fontSize: 12,
                        color: '#666',
                        overflow: 'hidden',
                        textOverflow: 'ellipsis',
                        display: '-webkit-box',
                        WebkitLineClamp: 2,
                        WebkitBoxOrient: 'vertical',
                      }}
                    >
                      {highlightMatches(item.snippet, item.matchedWords)}
                    </div>
                  }
                />
              </List.Item>
            )}
          />
        )}
      </div>
    </div>
  )
}

export default VectorSearchPanel

/**
 * 导出管理器
 * 支持 Markdown 和 EPUB 格式导出
 */

import path from 'path'

import { useState } from 'react'
import {
  Button,
  Space,
  Modal,
  Form,
  Select,
  Switch,
  message,
  Progress,
  Alert,
  Radio,
  Divider,
  List,
  Card,
  Tag,
  Input,
} from 'antd'
import {
  DownloadOutlined,
  FileMarkdownOutlined,
  BookOutlined,
  CheckCircleOutlined,
  FolderOpenOutlined,
} from '@ant-design/icons'

interface ExportManagerProps {
  projectRoot: string | null
  projectName?: string
  visible: boolean
  onClose: () => void
}

interface ChapterInfo {
  path: string
  name: string
  volume: string
  order: number
  content?: string
}

interface ExportProgress {
  current: number
  total: number
  status: 'idle' | 'exporting' | 'done' | 'error'
  message: string
}

const ExportManager: React.FC<ExportManagerProps> = ({
  projectRoot,
  projectName = '小说',
  visible,
  onClose,
}) => {
  const [exportFormat, setExportFormat] = useState<'markdown' | 'epub'>('markdown')
  const [exportMode, setExportMode] = useState<'single' | 'byVolume'>('single')
  const [includeToc, setIncludeToc] = useState(true)
  const [progress, setProgress] = useState<ExportProgress>({
    current: 0,
    total: 0,
    status: 'idle',
    message: '',
  })
  const [exportPath, setExportPath] = useState<string | null>(null)

  // 加载所有章节
  const loadChapters = async (): Promise<ChapterInfo[]> => {
    if (!projectRoot) return []

    const chapters: ChapterInfo[] = []

    const readDir = async (dirPath: string, volumeName: string = '正文') => {
      try {
        const entriesResult = await window.electronAPI.readdir(dirPath)
        if (!entriesResult.success) { console.warn('读取目录失败:', dirPath, entriesResult.error); return; }
        const entries = entriesResult.data || []
        for (const entry of entries) {
          const fullPath = `${dirPath}/${entry.name}`
          if (entry.isDirectory) {
            await readDir(fullPath, entry.name)
          } else if (entry.isFile && entry.name.endsWith('.md') && !entry.name.startsWith('_')) {
            const contentResult = await window.electronAPI.readFile(fullPath)
            if (contentResult.success && contentResult.content) {
              // 提取章节序号
              const orderMatch = entry.name.match(/第(\d+)章/)
              chapters.push({
                path: fullPath,
                name: entry.name.replace('.md', ''),
                volume: volumeName,
                order: orderMatch ? parseInt(orderMatch[1]) : 0,
                content: contentResult.content,
              })
            }
          }
        }
      } catch (e) {
        console.warn('读取目录失败:', dirPath, e)
      }
    }

    const plotsDir = `${projectRoot}/plots`
    const existsResult = await window.electronAPI.exists(plotsDir)
    if (existsResult?.success && existsResult?.exists) {
      await readDir(plotsDir)
    }

    return chapters.sort((a, b) => {
      if (a.volume !== b.volume) return a.volume.localeCompare(b.volume)
      return a.order - b.order
    })
  }

  // 导出 Markdown
  const exportMarkdown = async () => {
    if (!projectRoot) return

    setProgress({ current: 0, total: 0, status: 'exporting', message: '加载章节...' })

    try {
      const chapters = await loadChapters()
      if (chapters.length === 0) {
        message.warning('没有找到可导出的章节')
        setProgress({ current: 0, total: 0, status: 'error', message: '没有找到章节' })
        return
      }

      // 读取 project.yaml 获取标题
      let title = projectName
      try {
        const projectResult = await window.electronAPI.yaml.read(`${projectRoot}/project.yaml`)
        if (projectResult.success && projectResult.data) {
          const data = projectResult.data as Record<string, unknown>
          if (data.title) title = String(data.title)
        }
      } catch {}

      setProgress({ current: 0, total: chapters.length, status: 'exporting', message: '正在导出...' })

      if (exportMode === 'single') {
        // 单文件导出
        let toc = ''
        if (includeToc) {
          toc = `# ${title}\n\n`
          toc += `> 导出时间：${new Date().toLocaleString()}\n\n`
          toc += `## 目录\n\n`
          const volumes = [...new Set(chapters.map(c => c.volume))]
          for (const vol of volumes) {
            toc += `### ${vol}\n\n`
            const volChapters = chapters.filter(c => c.volume === vol)
            for (const ch of volChapters) {
              toc += `- [${ch.name}](#${ch.name.replace(/\s/g, '-')})\n`
            }
            toc += '\n'
          }
          toc += '---\n\n'
        }

        let fullContent = toc

        // 按卷分组
        const volumes = [...new Set(chapters.map(c => c.volume))]
        for (const vol of volumes) {
          fullContent += `\n\n# ${vol}\n\n`
          const volChapters = chapters.filter(c => c.volume === vol)

          for (let i = 0; i < volChapters.length; i++) {
            const ch = volChapters[i]
            setProgress({
              current: i + 1,
              total: chapters.length,
              status: 'exporting',
              message: `正在处理: ${ch.name}`,
            })

            fullContent += `\n\n## ${ch.name}\n\n`
            fullContent += ch.content || ''
          }
        }

        // 选择导出位置
        const parentDir = await window.electronAPI.openDirectory()
        if (!parentDir || parentDir.trim() === '') {
          setProgress({ current: 0, total: 0, status: 'idle', message: '' })
          return
        }

        const exportFile = path.join(parentDir, `${title}.md`)
        try {
          const writeResult = await window.electronAPI.writeFile(exportFile, fullContent)
          if (!writeResult.success) throw new Error(writeResult.error || '写入失败')
          setExportPath(exportFile)
          setProgress({ current: chapters.length, total: chapters.length, status: 'done', message: '导出完成' })
          message.success(`已导出到: ${exportFile}`)
        } catch (err) {
          message.error(`导出失败: ${(err as Error).message}`)
          setProgress({ current: 0, total: 0, status: 'error', message: '导出失败' })
        }
      } else {
        // 按卷拆分导出
        const parentDir = await window.electronAPI.openDirectory()
        if (!parentDir) {
          setProgress({ current: 0, total: 0, status: 'idle', message: '' })
          return
        }

        const volumes = [...new Set(chapters.map(c => c.volume))]
        for (let vi = 0; vi < volumes.length; vi++) {
          const vol = volumes[vi]
          const volChapters = chapters.filter(c => c.volume === vol)

          let volContent = `# ${vol}\n\n`
          if (includeToc) {
            volContent += `## 目录\n\n`
            for (const ch of volChapters) {
              volContent += `- [${ch.name}](#${ch.name.replace(/\s/g, '-')})\n`
            }
            volContent += '\n---\n\n'
          }

          for (let ci = 0; ci < volChapters.length; ci++) {
            const ch = volChapters[ci]
            setProgress({
              current: vi * volChapters.length + ci + 1,
              total: chapters.length,
              status: 'exporting',
              message: `正在处理: ${vol}/${ch.name}`,
            })

            volContent += `\n\n## ${ch.name}\n\n`
            volContent += ch.content || ''
          }

          const exportFile = `${parentDir}/${vol}.md`
          await window.electronAPI.writeFile(exportFile, volContent)
        }

        setExportPath(parentDir)
        setProgress({ current: chapters.length, total: chapters.length, status: 'done', message: '导出完成' })
        message.success(`已导出 ${volumes.length} 个文件到: ${parentDir}`)
      }
    } catch (error) {
      message.error('导出失败')
      setProgress({ current: 0, total: 0, status: 'error', message: '导出失败' })
    }
  }

  // 简单 HTML 转义
  const escapeHtml = (str: string): string => {
    return str
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;')
      .replace(/'/g, '&#39;')
  }

  // 转换为 EPUB XHTML
  const markdownToXhtml = (md: string, chapterTitle: string): string => {
    // 简单转换：处理标题和段落
    let html = md
      .replace(/^### (.+)$/gm, '<h3>$1</h3>')
      .replace(/^## (.+)$/gm, '<h2>$1</h2>')
      .replace(/^# (.+)$/gm, '<h1>$1</h1>')
      .replace(/\n\n/g, '</p><p>')
      .replace(/\n/g, '<br/>')

    return `<?xml version="1.0" encoding="UTF-8"?>
<html xmlns="http://www.w3.org/1999/xhtml">
<head>
  <title>${escapeHtml(chapterTitle)}</title>
  <style>
    body { font-family: "SimSun", serif; font-size: 1em; line-height: 1.6; margin: 1em; }
    h1, h2, h3 { text-align: center; margin: 1em 0; }
    p { text-indent: 2em; margin: 0.5em 0; }
  </style>
</head>
<body>
  <h1>${escapeHtml(chapterTitle)}</h1>
  <p>${html}</p>
</body>
</html>`
  }

  // 生成 EPUB
  const exportEpub = async () => {
    if (!projectRoot) return

    setProgress({ current: 0, total: 0, status: 'exporting', message: '加载章节...' })

    try {
      const chapters = await loadChapters()
      if (chapters.length === 0) {
        message.warning('没有找到可导出的章节')
        setProgress({ current: 0, total: 0, status: 'error', message: '没有找到章节' })
        return
      }

      // 读取 project.yaml
      let title = projectName
      let author = '未知作者'
      try {
        const projectResult = await window.electronAPI.yaml.read(`${projectRoot}/project.yaml`)
        if (projectResult.success && projectResult.data) {
          const data = projectResult.data as Record<string, unknown>
          if (data.title) title = String(data.title)
          if (data.author) author = String(data.author)
        }
      } catch {}

      // 选择导出位置
      const parentDir = await window.electronAPI.openDirectory()
      if (!parentDir) {
        setProgress({ current: 0, total: 0, status: 'idle', message: '' })
        return
      }

      const safeTitle = title.replace(/[^\w\u4e00-\u9fa5]/g, '_')
      const epubDir = `${parentDir}/${safeTitle}_epub`
      const metaResult = await window.electronAPI.mkdir(`${epubDir}/META-INF`)
      if (!metaResult.success) { throw new Error(metaResult.error || '创建META-INF失败') }
      const chaptersResult = await window.electronAPI.mkdir(`${epubDir}/OEBPS/chapters`)
      if (!chaptersResult.success) { throw new Error(chaptersResult.error || '创建OEBPS/chapters失败') }

      // mimetype（不压缩）
      await window.electronAPI.writeFile(`${epubDir}/mimetype`, 'application/epub+zip')

      // container.xml
      const container = `<?xml version="1.0" encoding="UTF-8"?>
<container version="1.0" xmlns="urn:oasis:names:tc:opendocument:xmlns:container">
  <rootfiles>
    <rootfile full-path="OEBPS/content.opf" media-type="application/oebps-package+xml"/>
  </rootfiles>
</container>`
      await window.electronAPI.writeFile(`${epubDir}/META-INF/container.xml`, container)

      // 生成 content.opf
      let spineItems = ''
      let manifestItems = ''
      for (let i = 0; i < chapters.length; i++) {
        const ch = chapters[i]
        const chFileName = `chapter_${String(i + 1).padStart(3, '0')}.xhtml`
        manifestItems += `    <item id="ch${i + 1}" href="chapters/${chFileName}" media-type="application/xhtml+xml"/>\n`
        spineItems += `    <itemref idref="ch${i + 1}"/>\n`
      }

      const contentOpf = `<?xml version="1.0" encoding="UTF-8"?>
<package xmlns="http://www.idpf.org/2007/opf" unique-identifier="BookId" version="2.0">
  <metadata xmlns:dc="http://purl.org/dc/elements/1.1/">
    <dc:title>${escapeHtml(title)}</dc:title>
    <dc:creator>${escapeHtml(author)}</dc:creator>
    <dc:language>zh-CN</dc:language>
    <dc:identifier id="BookId">urn:uuid:${Date.now()}</dc:identifier>
  </metadata>
  <manifest>
    ${manifestItems}
    <item id="ncx" href="toc.ncx" media-type="application/x-dtbncx+xml"/>
    <item id="toc" href="toc.xhtml" media-type="application/xhtml+xml"/>
  </manifest>
  <spine toc="ncx">
${spineItems}
  </spine>
</package>`
      await window.electronAPI.writeFile(`${epubDir}/OEBPS/content.opf`, contentOpf)

      // 生成 toc.ncx
      let navPoints = ''
      for (let i = 0; i < chapters.length; i++) {
        const ch = chapters[i]
        const chFileName = `chapter_${String(i + 1).padStart(3, '0')}.xhtml`
        navPoints += `    <navPoint id="navpoint-${i + 1}" playOrder="${i + 1}">
      <navLabel><text>${escapeHtml(ch.name)}</text></navLabel>
      <content src="chapters/${chFileName}"/>
    </navPoint>\n`
      }

      const tocNcx = `<?xml version="1.0" encoding="UTF-8"?>
<ncx xmlns="http://www.dgipart.org/2007/ncx" version="2005-1">
  <head>
    <meta name="dtb:uid" content="urn:uuid:${Date.now()}"/>
    <meta name="dtb:depth" content="1"/>
    <meta name="dtb:totalPageCount" content="0"/>
    <meta name="dtb:maxPageNumber" content="0"/>
  </head>
  <docTitle><text>${escapeHtml(title)}</text></docTitle>
  <navMap>
${navPoints}
  </navMap>
</ncx>`
      await window.electronAPI.writeFile(`${epubDir}/OEBPS/toc.ncx`, tocNcx)

      // 生成章节内容
      for (let i = 0; i < chapters.length; i++) {
        const ch = chapters[i]
        setProgress({
          current: i + 1,
          total: chapters.length,
          status: 'exporting',
          message: `正在处理: ${ch.name}`,
        })

        const chFileName = `chapter_${String(i + 1).padStart(3, '0')}.xhtml`
        const xhtmlContent = markdownToXhtml(ch.content || '', ch.name)
        await window.electronAPI.writeFile(`${epubDir}/OEBPS/chapters/${chFileName}`, xhtmlContent)
      }

      // 生成 toc.xhtml (HTML目录)
      let tocHtml = `<?xml version="1.0" encoding="UTF-8"?>
<html xmlns="http://www.w3.org/1999/xhtml">
<head><title>目录</title></head>
<body>
<h1>目录</h1>
<nav xmlns="http://www.w3.org/1999/xhtml"><ol>`
      for (let i = 0; i < chapters.length; i++) {
        const ch = chapters[i]
        const chFileName = `chapter_${String(i + 1).padStart(3, '0')}.xhtml`
        tocHtml += `<li><a href="chapters/${chFileName}">${escapeHtml(ch.name)}</a></li>`
      }
      tocHtml += '</ol></nav></body></html>'
      await window.electronAPI.writeFile(`${epubDir}/OEBPS/toc.xhtml`, tocHtml)

      setExportPath(epubDir)
      setProgress({ current: chapters.length, total: chapters.length, status: 'done', message: 'EPUB结构已生成' })
      message.success(`EPUB 文件结构已生成到: ${epubDir}\n请使用 epub 生成工具打包为 .epub 文件`)
    } catch (error) {
      message.error('EPUB 导出失败')
      setProgress({ current: 0, total: 0, status: 'error', message: '导出失败' })
    }
  }

  // 执行导出
  const handleExport = async () => {
    if (!projectRoot) {
      message.warning('请先打开项目')
      return
    }

    if (exportFormat === 'markdown') {
      await exportMarkdown()
    } else {
      await exportEpub()
    }
  }

  const handleOpenExport = () => {
    if (exportPath) {
      window.electronAPI.openPath(exportPath)
    }
  }

  return (
    <Modal
      title="📦 导出小说"
      open={visible}
      onCancel={onClose}
      width={500}
      footer={null}
      bodyStyle={{ maxHeight: '70vh', overflow: 'auto' }}
    >
      <div>
        <Alert
          message="导出功能可以将您的章节内容导出为标准格式，便于在其他平台发布"
          type="info"
          showIcon
          style={{ marginBottom: 16 }}
        />

        <Form layout="vertical">
          <Form.Item label="导出格式">
            <Radio.Group
              value={exportFormat}
              onChange={(e) => setExportFormat(e.target.value)}
            >
              <Radio.Button value="markdown">
                <FileMarkdownOutlined /> Markdown
              </Radio.Button>
              <Radio.Button value="epub">
                <BookOutlined /> EPUB
              </Radio.Button>
            </Radio.Group>
          </Form.Item>

          <Form.Item label="导出模式">
            <Radio.Group
              value={exportMode}
              onChange={(e) => setExportMode(e.target.value)}
            >
              <Radio value="single">单文件</Radio>
              <Radio value="byVolume">按卷拆分</Radio>
            </Radio.Group>
          </Form.Item>

          <Form.Item label="目录">
            <Switch checked={includeToc} onChange={setIncludeToc} />
            <span style={{ marginLeft: 8, color: '#666', fontSize: 12 }}>
              {includeToc ? '包含目录' : '不包含目录'}
            </span>
          </Form.Item>

          <Divider />

          {progress.status === 'exporting' && (
            <div style={{ marginBottom: 16 }}>
              <Progress
                percent={progress.total > 0 ? Math.round((progress.current / progress.total) * 100) : 0}
                status="active"
                format={(percent) => `${progress.current}/${progress.total}`}
              />
              <div style={{ fontSize: 12, color: '#666', textAlign: 'center' }}>
                {progress.message}
              </div>
            </div>
          )}

          {progress.status === 'done' && (
            <Alert
              message="导出完成！"
              description={exportPath}
              type="success"
              showIcon
              style={{ marginBottom: 16 }}
              action={
                <Button size="small" icon={<FolderOpenOutlined />} onClick={handleOpenExport}>
                  打开
                </Button>
              }
            />
          )}

          <Space>
            <Button
              type="primary"
              icon={<DownloadOutlined />}
              onClick={handleExport}
              loading={progress.status === 'exporting'}
              disabled={!projectRoot}
            >
              开始导出
            </Button>
            <Button onClick={onClose}>
              关闭
            </Button>
          </Space>
        </Form>
      </div>
    </Modal>
  )
}

export default ExportManager

/**
 * AI 工具面板
 * 包含：智能续写、定向扩写、逻辑校验、提取事实、AI重写、AI润色、语法检查、大纲生成、风格迁移
 */

import { useState } from 'react'
import {
  Button,
  Space,
  Card,
  Input,
  message,
  Spin,
  Modal,
  Select,
  Divider,
  Tabs,
  Alert,
  Radio,
  Slider,
} from 'antd'
import {
  EditOutlined,
  ExpandOutlined,
  CheckCircleOutlined,
  ThunderboltOutlined,
  SaveOutlined,
  SyncOutlined,
  BulbOutlined,
  BgColorsOutlined,
  ProfileOutlined,
  ScissorOutlined,
} from '@ant-design/icons'
import aiModelService from '../services/aiModels'
import factExtractor, { ExtractedFact } from '../services/factExtractor'

const { TextArea } = Input

interface AIToolsPanelProps {
  chapterContent: string
  chapterPath: string | null
  getSelectedText: () => string
  onInsertText: (text: string) => void
}

type RewriteMode = 'concise' | 'expand' | 'improve'
type RewriteScope = 'chapter' | 'paragraph'

const STYLE_OPTIONS = [
  { value: '金庸', label: '金庸（武侠古典）' },
  { value: '猫腻', label: '猫腻（文笔华丽）' },
  { value: '烽火戏诸侯', label: '烽火戏诸侯（热血燃系）' },
  { value: '乌山居', label: '乌山居（简洁流畅）' },
  { value: '辰东', label: '辰东（宏大壮阔）' },
  { value: '土豆', label: '土豆（小白文爽文）' },
  { value: '古龙', label: '古龙（简洁悬疑）' },
  { value: '鲁迅', label: '鲁迅（深刻犀利）' },
  { value: '海明威', label: '海明威（简洁有力）' },
]

const AIToolsPanel = ({ chapterContent, chapterPath, getSelectedText, onInsertText }: AIToolsPanelProps) => {
  const [generating, setGenerating] = useState(false)
  const [result, setResult] = useState('')
  const [prompt, setPrompt] = useState('')
  const [extractedFacts, setExtractedFacts] = useState<ExtractedFact[]>([])
  const [activeTool, setActiveTool] = useState<string>('continue')

  // 智能续写
  const handleContinue = async () => {
    if (!chapterContent) {
      message.warning('请先选择章节并编写内容')
      return
    }
    setActiveTool('continue')
    setGenerating(true)
    setResult('')

    try {
      const context = chapterContent.slice(-800)
      const fullPrompt = `请继续写下面的小说内容，风格保持一致，衔接自然：

${context}

续写内容（请直接输出续写文本，不需要加标题）：`

      await aiModelService.stream(
        'creative',
        fullPrompt,
        (chunk) => setResult(prev => prev + chunk),
        (error) => { message.error(`续写失败：${error}`); setGenerating(false); }
      )
    } catch (error) {
      message.error('续写失败')
    } finally {
      setGenerating(false)
    }
  }

  // 定向扩写
  const handleExpand = async () => {
    if (!prompt) {
      message.warning('请输入扩写要求')
      return
    }
    if (!chapterContent) {
      message.warning('请先选择章节')
      return
    }
    setActiveTool('expand')
    setGenerating(true)
    setResult('')

    try {
      const fullPrompt = `请根据以下要求扩写小说内容。要求：${prompt}

当前章节上下文：
${chapterContent.slice(-1200)}

扩写后的内容（请直接输出扩写文本）：`

      await aiModelService.stream(
        'creative',
        fullPrompt,
        (chunk) => setResult(prev => prev + chunk),
        (error) => { message.error(`扩写失败：${error}`); setGenerating(false); }
      )
    } catch (error) {
      message.error('扩写失败')
    } finally {
      setGenerating(false)
    }
  }

  // 逻辑校验
  const handleCheck = async () => {
    if (!chapterContent) {
      message.warning('请先选择章节')
      return
    }
    setActiveTool('check')
    setGenerating(true)
    setResult('')

    try {
      const checkResult = await aiModelService.call(
        'logic',
        chapterContent,
        {
          systemPrompt: `请检查以下小说章节内容的逻辑一致性，找出矛盾点、战力崩坏、情节不合理的地方，给出修改建议。请使用清晰的格式输出检查结果。`
        }
      )

      if (checkResult.success && checkResult.content) {
        setResult(checkResult.content)
      } else {
        message.error(checkResult.error || '校验失败')
      }
    } catch (error) {
      message.error('逻辑校验失败')
    } finally {
      setGenerating(false)
    }
  }

  // 提取事实
  const handleExtract = async () => {
    if (!chapterContent || !chapterPath) {
      message.warning('请先选择章节')
      return
    }
    setActiveTool('extract')
    setGenerating(true)
    setResult('')

    try {
      const chapterMatch = chapterPath.match(/第(\d+)章/)
      const chapterNumber = chapterMatch ? parseInt(chapterMatch[1]) : 1

      const facts = await factExtractor.extract(chapterContent, chapterNumber)
      setExtractedFacts(facts)

      if (facts.length === 0) {
        setResult('未提取到任何事实')
        return
      }

      let output = `提取到 ${facts.length} 条事实：\n\n`
      facts.forEach((fact, index) => {
        output += `${index + 1}. [${fact.type}] ${fact.subject}${fact.object ? ' → ' + fact.object : ''}\n`
        output += `   ${fact.content} (置信度: ${(fact.confidence * 100).toFixed(0)}%)\n\n`
      })

      output += `\n点击「保存到台账」将以上事实追加写入 facts YAML 文件。`
      setResult(output)
    } catch (error) {
      message.error('事实提取失败')
    } finally {
      setGenerating(false)
    }
  }

  // 保存提取的事实到 facts 台账
  const handleSaveFacts = async () => {
    if (extractedFacts.length === 0) return
    setGenerating(true)
    try {
      const chapterMatch = chapterPath?.match(/第(\d+)章/)
      const chapterNumber = chapterMatch ? parseInt(chapterMatch[1]) : 1
      const saved = await factExtractor.extractAndSave(chapterContent, chapterNumber)
      if (saved.length > 0) {
        message.success(`已保存 ${saved.length} 条事实到台账`)
        setResult('')
        setExtractedFacts([])
      } else {
        message.error('保存失败')
      }
    } catch (error) {
      message.error('保存失败')
    } finally {
      setGenerating(false)
    }
  }

  // ── AI 重写（增强版）──────────────────────────────────────────────────────
  const [rewriteMode, setRewriteMode] = useState<RewriteMode>('improve')
  const [rewriteScope, setRewriteScope] = useState<RewriteScope>('chapter')
  const [rewritePromptText, setRewritePromptText] = useState('')

  const getRewritePromptForMode = (mode: RewriteMode): string => {
    const prompts: Record<RewriteMode, string> = {
      concise: '精简内容，去除冗余表达，使文字更加凝练有力',
      expand: '适度扩展细节描写，丰富场景和情感刻画',
      improve: '改善文笔和叙事节奏，提升整体可读性',
    }
    return prompts[mode]
  }

  const handleRewrite = async () => {
    if (!chapterContent) {
      message.warning('请先选择章节')
      return
    }
    setActiveTool('rewrite')
    setGenerating(true)
    setResult('')

    try {
      const modeText = rewriteMode === 'concise' ? '精简' : rewriteMode === 'expand' ? '扩展' : '改进'
      let rewriteInstruction = getRewritePromptForMode(rewriteMode)
      if (rewritePromptText) {
        rewriteInstruction += `。额外要求：${rewritePromptText}`
      }

      if (rewriteScope === 'paragraph') {
        const selectedText = getSelectedText()
        if (!selectedText || selectedText.length < 10) {
          message.warning('请先在编辑器中选中要重写的段落（至少10个字）')
          setGenerating(false)
          return
        }
        const fullPrompt = `请重写以下小说段落，保持情节和主题不变，但使文笔更优美：

原文：
${selectedText}

重写模式：${modeText}
要求：${rewriteInstruction}

重写后的内容（直接输出原文对照，重写文本用【】包裹）：`

        await aiModelService.stream(
          'creative',
          fullPrompt,
          (chunk) => setResult(prev => prev + chunk),
          (error) => { message.error(`重写失败：${error}`); setGenerating(false); }
        )
      } else {
        const fullPrompt = `请重写以下小说章节，保持情节和主题不变，但改善文笔和叙事：

原文：
${chapterContent.slice(-2000)}

重写模式：${modeText}
要求：${rewriteInstruction}

重写后的内容（直接输出，不要加标题或说明）：`

        await aiModelService.stream(
          'creative',
          fullPrompt,
          (chunk) => setResult(prev => prev + chunk),
          (error) => { message.error(`重写失败：${error}`); setGenerating(false); }
        )
      }
    } catch (error) {
      message.error('重写失败')
    } finally {
      setGenerating(false)
    }
  }

  // ── AI 润色 ─────────────────────────────────────────────────────────────
  const handlePolish = async () => {
    if (!chapterContent) {
      message.warning('请先选择章节')
      return
    }
    setActiveTool('polish')
    setGenerating(true)
    setResult('')

    try {
      const fullPrompt = `请对以下小说内容进行文笔润色，改善表达流畅度、精简冗余、提升文字质感，但不改变原意和情节：

原文：
${chapterContent.slice(-1500)}

润色后的内容（直接输出，不要加说明）：`

      await aiModelService.stream(
        'creative',
        fullPrompt,
        (chunk) => setResult(prev => prev + chunk),
        (error) => { message.error(`润色失败：${error}`); setGenerating(false); }
      )
    } catch (error) {
      message.error('润色失败')
    } finally {
      setGenerating(false)
    }
  }

  // ── 语法检查 ─────────────────────────────────────────────────────────────
  const handleGrammarCheck = async () => {
    if (!chapterContent) {
      message.warning('请先选择章节')
      return
    }
    setActiveTool('grammar')
    setGenerating(true)
    setResult('')

    try {
      const fullPrompt = `请检查以下小说内容中的语法错误、病句、错别字、标点错误，用【原文 → 修改后】的格式列出所有问题并给出修改建议。如果没有错误，请明确说明：

原文：
${chapterContent.slice(-1500)}

检查结果（格式示例）：
1. 【"他快速的跑过来" → "他快速地跑过来"】错别字+病句
2. 【"小明和小华是好朋友，他们经常一起玩" → "小明和小华是好朋友，他们经常一起玩耍"】用词更准确` as string

      await aiModelService.stream(
        'logic',
        fullPrompt,
        (chunk) => setResult(prev => prev + chunk),
        (error) => { message.error(`检查失败：${error}`); setGenerating(false); }
      )
    } catch (error) {
      message.error('语法检查失败')
    } finally {
      setGenerating(false)
    }
  }

  // ── 大纲生成 ─────────────────────────────────────────────────────────────
  const [outlineMode, setOutlineMode] = useState<'chapter' | 'full'>('chapter')

  const handleGenerateOutline = async () => {
    if (!chapterContent) {
      message.warning('请先选择章节')
      return
    }
    setActiveTool('outline')
    setGenerating(true)
    setResult('')

    try {
      if (outlineMode === 'chapter') {
        const fullPrompt = `请分析以下章节内容，生成该章节的详细写作大纲，包括：
1. 本章核心事件
2. 主要情节点（按顺序列出）
3. 角色出场安排
4. 高潮和转折点
5. 伏笔铺设（如有）

章节内容：
${chapterContent}

章节大纲（格式清晰）：`

        await aiModelService.stream(
          'summary',
          fullPrompt,
          (chunk) => setResult(prev => prev + chunk),
          (error) => { message.error(`大纲生成失败：${error}`); setGenerating(false); }
        )
      } else {
        const fullPrompt = `请根据以下已知章节内容，为这本小说生成整体大纲框架（包括：
- 主线剧情概述
- 主要角色弧光
- 关键情节点（起承转合）
- 世界观核心设定
- 伏笔和悬念布局

已有章节内容：
${chapterContent.slice(0, 3000)}

整体大纲框架：`

        await aiModelService.stream(
          'summary',
          fullPrompt,
          (chunk) => setResult(prev => prev + chunk),
          (error) => { message.error(`大纲生成失败：${error}`); setGenerating(false); }
        )
      }
    } catch (error) {
      message.error('大纲生成失败')
    } finally {
      setGenerating(false)
    }
  }

  // ── 风格迁移 ─────────────────────────────────────────────────────────────
  const [selectedStyle, setSelectedStyle] = useState<string>('')
  const [styleStrength, setStyleStrength] = useState<number>(80)

  const handleStyleTransfer = async () => {
    if (!chapterContent) {
      message.warning('请先选择章节')
      return
    }
    if (!selectedStyle) {
      message.warning('请选择目标风格')
      return
    }
    setActiveTool('style')
    setGenerating(true)
    setResult('')

    try {
      const styleInfo = STYLE_OPTIONS.find(s => s.value === selectedStyle)
      const strengthDesc = styleStrength > 80 ? '强烈' : styleStrength > 50 ? '中等' : '轻微'
      const fullPrompt = `请用"${styleInfo?.label}"的风格重写以下小说内容。保持情节不变，但采用该作家特有的叙事风格、文笔特点。风格强度：${strengthDesc}（${styleStrength}%）。

原文：
${chapterContent.slice(-1500)}

风格迁移后的内容（直接输出）：`

      await aiModelService.stream(
        'creative',
        fullPrompt,
        (chunk) => setResult(prev => prev + chunk),
        (error) => { message.error(`风格迁移失败：${error}`); setGenerating(false); }
      )
    } catch (error) {
      message.error('风格迁移失败')
    } finally {
      setGenerating(false)
    }
  }

  // 应用生成结果
  const handleApply = () => {
    if (!result) return
    Modal.confirm({
      title: '插入方式',
      content: '选择如何将生成内容插入编辑器：',
      okText: '追加到末尾',
      cancelText: '取消',
      onOk: () => {
        onInsertText(result)
        message.success('已追加到编辑器')
        setResult('')
      },
    })
  }

  // 替换全文
  const handleReplace = () => {
    if (!result) return
    Modal.confirm({
      title: '确认替换',
      content: '将使用生成的内容完全替换当前章节内容？',
      okText: '确认替换',
      okButtonProps: { danger: true },
      cancelText: '取消',
      onOk: () => {
        onInsertText(`__REPLACE__${result}`)
        message.success('已替换章节内容')
        setResult('')
      },
    })
  }

  // 将结果插入到光标位置
  const handleInsertAtCursor = () => {
    if (!result) return
    onInsertText(result)
    message.success('已插入到编辑器')
    setResult('')
  }

  const isReplacingTool = ['rewrite', 'polish', 'style', 'grammar'].includes(activeTool)

  return (
    <div style={{ height: '100%', display: 'flex', flexDirection: 'column' }}>
      {/* 工具标签页 */}
      <div style={{ padding: '10px 16px 0', borderBottom: '1px solid #e8e8e8' }}>
        <Tabs
          activeKey={activeTool}
          onChange={(key) => {
            setActiveTool(key)
            setResult('')
            setExtractedFacts([])
          }}
          size="small"
          items={[
            {
              key: 'writing',
              label: '✏️ 写作',
              children: (
                <div>
                  <Space direction="vertical" style={{ width: '100%' }}>
                    <Button
                      type="primary"
                      block
                      icon={<EditOutlined />}
                      onClick={handleContinue}
                      loading={generating && activeTool === 'continue'}
                      disabled={!chapterContent}
                    >
                      智能续写
                    </Button>
                    <Button
                      block
                      icon={<ExpandOutlined />}
                      onClick={handleExpand}
                      loading={generating && activeTool === 'expand'}
                      disabled={!chapterContent}
                    >
                      定向扩写
                    </Button>
                    <Button
                      block
                      icon={<SyncOutlined />}
                      onClick={handleRewrite}
                      loading={generating && activeTool === 'rewrite'}
                      disabled={!chapterContent}
                    >
                      AI重写
                    </Button>
                    <Button
                      block
                      icon={<BgColorsOutlined />}
                      onClick={handlePolish}
                      loading={generating && activeTool === 'polish'}
                      disabled={!chapterContent}
                    >
                      AI润色
                    </Button>
                    <Button
                      block
                      icon={<ScissorOutlined />}
                      onClick={handleGrammarCheck}
                      loading={generating && activeTool === 'grammar'}
                      disabled={!chapterContent}
                    >
                      语法检查
                    </Button>

                    <TextArea
                      placeholder="扩写/重写要求（可选）"
                      rows={2}
                      value={prompt}
                      onChange={(e) => setPrompt(e.target.value)}
                    />
                  </Space>

                  {activeTool === 'rewrite' && (
                    <div style={{ marginTop: 8 }}>
                      <div style={{ marginBottom: 6 }}>
                        <span style={{ fontSize: 11, color: '#666' }}>重写范围：</span>
                        <Radio.Group
                          value={rewriteScope}
                          onChange={(e) => setRewriteScope(e.target.value)}
                          size="small"
                          style={{ marginLeft: 4 }}
                        >
                          <Radio.Button value="chapter">整章</Radio.Button>
                          <Radio.Button value="paragraph">段落</Radio.Button>
                        </Radio.Group>
                        {rewriteScope === 'paragraph' && (
                          <Alert
                            message="请先在编辑器中选中要重写的段落"
                            type="info"
                            style={{ marginTop: 4, fontSize: 10 }}
                            showIcon
                          />
                        )}
                      </div>
                      <div style={{ marginBottom: 6 }}>
                        <span style={{ fontSize: 11, color: '#666' }}>重写模式：</span>
                        <Radio.Group
                          value={rewriteMode}
                          onChange={(e) => setRewriteMode(e.target.value)}
                          size="small"
                          style={{ marginLeft: 4 }}
                        >
                          <Radio.Button value="concise">精简</Radio.Button>
                          <Radio.Button value="expand">扩展</Radio.Button>
                          <Radio.Button value="improve">改进</Radio.Button>
                        </Radio.Group>
                      </div>
                      <Input
                        placeholder="重写额外要求（可选）"
                        size="small"
                        value={rewritePromptText}
                        onChange={(e) => setRewritePromptText(e.target.value)}
                        style={{ width: '100%' }}
                      />
                    </div>
                  )}

                  {activeTool === 'polish' && (
                    <Alert
                      message="润色将改善文笔表达，精简冗余，但保持原意"
                      type="info"
                      showIcon
                      style={{ marginTop: 8, fontSize: 11 }}
                    />
                  )}

                  {activeTool === 'grammar' && (
                    <Alert
                      message="检查语法错误、病句、错别字、标点错误"
                      type="info"
                      showIcon
                      style={{ marginTop: 8, fontSize: 11 }}
                    />
                  )}
                </div>
              ),
            },
            {
              key: 'review',
              label: '🔍 校验',
              children: (
                <div>
                  <Space direction="vertical" style={{ width: '100%' }}>
                    <Button
                      block
                      icon={<CheckCircleOutlined />}
                      onClick={handleCheck}
                      loading={generating && activeTool === 'check'}
                      disabled={!chapterContent}
                    >
                      逻辑校验
                    </Button>
                    <Button
                      block
                      icon={<ThunderboltOutlined />}
                      onClick={handleExtract}
                      loading={generating && activeTool === 'extract'}
                      disabled={!chapterContent}
                    >
                      提取事实
                    </Button>
                  </Space>
                </div>
              ),
            },
            {
              key: 'outline',
              label: '📋 大纲',
              children: (
                <div>
                  <Space direction="vertical" style={{ width: '100%' }}>
                    <Button
                      block
                      icon={<ProfileOutlined />}
                      onClick={() => {
                        setOutlineMode('chapter')
                        handleGenerateOutline()
                      }}
                      loading={generating && activeTool === 'outline'}
                      disabled={!chapterContent}
                    >
                      生成本章大纲
                    </Button>
                    <Button
                      block
                      icon={<BulbOutlined />}
                      onClick={() => {
                        setOutlineMode('full')
                        handleGenerateOutline()
                      }}
                      loading={generating && activeTool === 'outline'}
                      disabled={!chapterContent}
                    >
                      生成整体大纲
                    </Button>
                    <Divider style={{ margin: '8px 0' }} />
                    <Select
                      placeholder="选择风格"
                      value={selectedStyle || undefined}
                      onChange={setSelectedStyle}
                      options={STYLE_OPTIONS}
                      style={{ width: '100%' }}
                      allowClear
                    />
                    {selectedStyle && (
                      <div>
                        <span style={{ fontSize: 11, color: '#666' }}>风格强度：{styleStrength}%</span>
                        <Slider
                          value={styleStrength}
                          onChange={setStyleStrength}
                          min={20}
                          max={100}
                          step={10}
                          marks={{ 20: '轻', 50: '中', 80: '强', 100: '极' }}
                        />
                      </div>
                    )}
                    <Button
                      block
                      icon={<BgColorsOutlined />}
                      onClick={handleStyleTransfer}
                      loading={generating && activeTool === 'style'}
                      disabled={!chapterContent || !selectedStyle}
                    >
                      风格迁移
                    </Button>
                  </Space>
                </div>
              ),
            },
          ]}
        />
      </div>

      {/* 结果显示区 */}
      <div style={{ flex: 1, overflow: 'auto', padding: 16 }}>
        {generating ? (
          <div style={{ textAlign: 'center', padding: 40 }}>
            <Spin tip="AI 生成中..." />
          </div>
        ) : result ? (
          <Card
            size="small"
            title="生成结果"
            extra={
              <Space>
                {extractedFacts.length > 0 && (
                  <Button
                    type="primary"
                    size="small"
                    icon={<SaveOutlined />}
                    onClick={handleSaveFacts}
                    loading={generating}
                  >
                    保存到台账
                  </Button>
                )}
                <Button type="link" size="small" onClick={handleInsertAtCursor}>
                  插入光标
                </Button>
                <Button type="link" size="small" onClick={handleApply}>
                  追加
                </Button>
                {isReplacingTool && (
                  <Button type="link" size="small" onClick={handleReplace} danger>
                    替换全文
                  </Button>
                )}
              </Space>
            }
            style={{ whiteSpace: 'pre-wrap', wordBreak: 'break-all' }}
          >
            {result}
          </Card>
        ) : (
          <div style={{ color: '#999', textAlign: 'center', padding: 40 }}>
            选择上方工具开始使用 AI 辅助创作
          </div>
        )}
      </div>
    </div>
  )
}

export default AIToolsPanel

